<template>
  <div class="aaa">
    <word />
    <blog :datas="datas" />
    <el-pagination
      background
      layout="prev, pager, next"
      class="a"
      :total="total"
      :page-size="pageSize"
      @current-change="handle"
      :current-page="currentPage"
    ></el-pagination>
  </div>
</template>

<script>
import word from "./Word";
import blog from "./Article";

import axios from "axios";
export default {
  components: {
    word,
    blog
  },
  created() {
    this.keyword = this.$route.query.keyword;
    axios
      .get("/api/article/seek", {
        params: {
          keyword: this.keyword
        }
      })
      .then(res => {
        this.datas = res.data.datas;
        this.total = res.data.total;
      });
  },
  watch: {
    $route(to, from) {
      this.keyword = to.query.keyword;
      axios
        .get("/api/article/seek", {
          params: {
            keyword: this.keyword
          }
        })
        .then(res => {
          this.datas = res.data.datas;
          this.total = res.data.total;
          if(this.datas === null || this.datas.length ===0){
              alert('没找到该文章呢')
          }
        });
    }
  },
  data() {
    return {
      keyword: "",
      datas: [],
      total: 10,
      currentPage: 1,
      pageSize: 7
    };
  },
  methods: {
    handle(newPage) {
      this.currentPage = newPage;
      axios
        .get("/api/article/seek", {
          params: {
              keyword: this.keyword,
            page: newPage,
            pageSize: this.pageSize
          }
        })
        .then(res => {
            console.log(res)
          this.total = res.data.total;
          this.datas = res.data.datas;
        });
    }
  }
};
</script>

<style scoped>
.aaa {
  display: inline-block;
}
</style>